const Header: React.FC = () => {
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [visible, setVisible] = useState(true);
  const [prevScrollPos, setPrevScrollPos] = useState(0);

  useEffect(() => {
    const handleScroll = () => {
      const currentScrollPos = window.pageYOffset;
      const isScrollingUp = prevScrollPos > currentScrollPos;
      if (currentScrollPos < 50 || isSidebarOpen) setVisible(true);
      else setVisible(isScrollingUp);
      setPrevScrollPos(currentScrollPos);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, [prevScrollPos, isSidebarOpen]);

  useEffect(() => {
    document.body.style.overflow = isSidebarOpen ? 'hidden' : 'unset';
  }, [isSidebarOpen]);

  const menuItems = [
    { name: 'Home', href: '#' },
    { name: 'The Archive', href: '#fragments' },
    { name: 'Collections', href: '#collections' },
    { name: 'Why Amora', href: '#why-amary' },
    { name: 'Reviews', href: '#reviews' },
    { name: 'Heritage', href: '#heritage' },
    { name: 'Contact', href: '#contact' },
  ];

  const handleLinkClick = (e: React.MouseEvent<HTMLAnchorElement>, href: string) => {
    if (href.startsWith('#')) {
      e.preventDefault();
      const element = document.querySelector(href);
      if (element) {
        element.scrollIntoView({ behavior: 'smooth' });
        setIsSidebarOpen(false);
      } else if (href === '#') {
        window.scrollTo({ top: 0, behavior: 'smooth' });
        setIsSidebarOpen(false);
      }
    }
  };

  return (
    <>
      <header className={`fixed top-0 left-0 right-0 z-[100] bg-brand-light/95 backdrop-blur-xl transition-all duration-1000 ease-[cubic-bezier(0.23,1,0.32,1)] px-6 md:px-12 py-4 md:py-6 border-b border-black/5 ${visible ? 'translate-y-0 opacity-100 shadow-sm' : '-translate-y-full opacity-0'}`}>
        <div className="max-w-[1920px] mx-auto grid grid-cols-3 items-center">

          {/* Menu Trigger */}
          <div className="flex items-center">
            <button 
              onClick={() => setIsSidebarOpen(true)} 
              className="flex items-center gap-3 group text-brand-dark/80 hover:text-brand-gold transition-colors" 
              aria-label="Toggle Navigation"
            >
              <div className="relative w-5 h-5 flex flex-col justify-center gap-[4px]">
                <span className="w-5 h-[1px] bg-current transition-all duration-500 group-hover:w-3" />
                <span className="w-3 h-[1px] bg-current transition-all duration-500 group-hover:w-5" />
              </div>
              <span className="hidden md:block text-[9px] font-bold tracking-[0.3em] uppercase opacity-60 group-hover:opacity-100 transition-opacity">Menu</span>
            </button>
          </div>

          {/* Central Branding */}
          <div className="flex flex-col items-center gap-1 group cursor-pointer" onClick={(e) => handleLinkClick(e as any, '#')}>
            <div className="transform transition-transform duration-700 group-hover:scale-105">
