const Header: React.FC = () => {
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [visible, setVisible] = useState(true);
  const [prevScrollPos, setPrevScrollPos] = useState(0);

  useEffect(() => {
    const handleScroll = () => {
      const currentScrollPos = window.pageYOffset;
      const isScrollingUp = prevScrollPos > currentScrollPos;
      if (currentScrollPos < 50 || isSidebarOpen) setVisible(true);
      else setVisible(isScrollingUp);
      setPrevScrollPos(currentScrollPos);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, [prevScrollPos, isSidebarOpen]);

  useEffect(() => {
    document.body.style.overflow = isSidebarOpen ? 'hidden' : 'unset';
  }, [isSidebarOpen]);

  const menuItems = [
    { name: 'Home', href: '#' },
    { name: 'The Archive', href: '#fragments' },
    { name: 'Collections', href: '#collections' },
    { name: 'Philosophy', href: '#why-amary' },
    { name: 'Reviews', href: '#reviews' },
    { name: 'Contact', href: '#contact' },
  ];

  const handleLinkClick = (e: React.MouseEvent<HTMLAnchorElement>, href: string) => {
    if (href.startsWith('#')) {
      e.preventDefault();
      const element = document.querySelector(href);
      if (element) {
        element.scrollIntoView({ behavior: 'smooth' });
        setIsSidebarOpen(false);
      } else if (href === '#') {
        window.scrollTo({ top: 0, behavior: 'smooth' });
        setIsSidebarOpen(false);
      }
    }
  };

  return (
    <>
      <header className={`fixed top-0 left-0 right-0 z-[100] bg-brand-light/90 backdrop-blur-xl transition-all duration-700 ease-[cubic-bezier(0.23,1,0.32,1)] px-6 md:px-12 py-4 md:py-5 border-b border-black/[0.03] ${visible ? 'translate-y-0 opacity-100' : '-translate-y-full opacity-0'}`}>
        <div className="max-w-[1920px] mx-auto flex justify-between items-center">

          {/* Top Left: Logo + Branding */}
          <div 
            className="flex items-center gap-4 group cursor-pointer" 
            onClick={(e) => handleLinkClick(e as any, '#')}
          >
            <div className="transform transition-transform duration-500 group-hover:scale-105">
              <LogoAA className="w-9 h-9 md:w-11 md:h-11" />
            </div>
            <span className="font-serif text-[11px] md:text-[14px] font-bold text-brand-dark tracking-[0.5em] uppercase leading-none mt-0.5">
              AMARY AMORA
            </span>
          </div>

          {/* Top Right: Minimal Menu Button */}
          <div className="flex items-center">
            <button 
              onClick={() => setIsSidebarOpen(true)} 
              className="flex items-center gap-4 group text-brand-dark hover:text-brand-gold transition-colors duration-500" 
              aria-label="Toggle Navigation"
            >
              <span className="hidden sm:block text-[9px] font-bold tracking-[0.4em] uppercase opacity-40 group-hover:opacity-100 transition-opacity">Menu</span>
              <div className="flex flex-col gap-1.5 items-end">
                <span className="w-5 h-[1px] bg-brand-dark group-hover:bg-brand-gold transition-all duration-500" />
                <span className="w-3 h-[1px] bg-brand-dark group-hover:bg-brand-gold group-hover:w-5 transition-all duration-500" />
              </div>
            </button>
          </div>
        </div>
      </header>

      {/* Overlay */}
      <div 
        className={`fixed inset-0 z-[110] backdrop-blur-sm bg-black/5 transition-opacity duration-700 ease-in-out ${isSidebarOpen ? 'opacity-100 pointer-events-auto' : 'opacity-0 pointer-events-none'}`} 
        onClick={() => setIsSidebarOpen(false)} 
      />

      {/* Sidebar Navigation */}
      <div className={`fixed top-0 right-0 h-full w-full sm:w-[450px] z-[120] bg-brand-light shadow-[-40px_0_100px_rgba(0,0,0,0.08)] transition-transform duration-1000 ease-[cubic-bezier(0.23,1,0.32,1)] transform ${isSidebarOpen ? 'translate-x-0' : 'translate-x-full'}`}>
        <div className="h-full flex flex-col px-12 md:px-20 py-12">
          <div className="flex justify-between items-center mb-16">
            <LogoAA className="w-8 h-8 opacity-40" />
            <button 
              onClick={() => setIsSidebarOpen(false)} 
              className="group w-10 h-10 flex items-center justify-center rounded-full hover:bg-black/5 transition-colors"
            >
              <X size={20} strokeWidth={1.5} className="text-brand-dark/30 group-hover:text-brand-dark transition-colors" />
            </button>
          </div>

          <nav className="flex flex-col gap-10 flex-grow">
            {menuItems.map((item, index) => (
              <a 
                key={item.name} 
