const WhyAmary: React.FC = () => {
  const [activeIndex, setActiveIndex] = useState(0);
  const [isPaused, setIsPaused] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);

  // Auto-swipe logic
  useEffect(() => {
    if (isPaused) return;
    const interval = setInterval(() => {
      setActiveIndex((prev) => (prev + 1) % corePoints.length);
    }, 4000);
    return () => clearInterval(interval);
  }, [isPaused]);

  // Handle activeIndex changes (auto/manual buttons)
  useEffect(() => {
    if (containerRef.current) {
      const targetElement = containerRef.current.children[activeIndex] as HTMLElement;
      if (targetElement) {
        // We scroll to the element but keep it slightly offset so the previous one is also partially visible if desired
        // but typically snap-center handles the visual alignment.
        const scrollTarget = targetElement.offsetLeft - 24; // Slight padding offset
        containerRef.current.scrollTo({
          left: scrollTarget,
          behavior: 'smooth'
        });
      }
    }
  }, [activeIndex]);

  // Sync dots with manual scroll
  const handleScroll = () => {
    if (containerRef.current) {
      const scrollLeft = containerRef.current.scrollLeft;
      const width = containerRef.current.children[0].clientWidth + 32; // width + gap
      const newIndex = Math.round(scrollLeft / width);
      if (newIndex !== activeIndex && newIndex >= 0 && newIndex < corePoints.length) {
        setActiveIndex(newIndex);
      }
    }
  };

  const handleManualNav = (index: number) => {
    setActiveIndex(index);
    setIsPaused(true);
    setTimeout(() => setIsPaused(false), 6000);
  };

  return (
    <section 
      id="why-amary" 
      className="py-20 md:py-32 bg-white overflow-hidden relative"
