            onScroll={handleScroll}
            className="flex overflow-x-auto gap-8 pb-12 snap-x snap-mandatory no-scrollbar transition-all duration-1000 ease-[cubic-bezier(0.23,1,0.32,1)] scroll-smooth px-2"
          >
            {corePoints.map((point, index) => (
              <div 
                key={point.id} 
                className="flex-shrink-0 w-[65vw] sm:w-[35vw] md:w-[28vw] lg:w-[20vw] snap-start relative aspect-[4/5] rounded-[2.5rem] overflow-hidden group/card shadow-[0_15px_40px_rgba(0,0,0,0.04)] transition-all duration-[1.5s] ease-[cubic-bezier(0.23,1,0.32,1)]"
              >
                <img 
                  src={point.image} 
                  alt={point.title}
                  className="w-full h-full object-cover brightness-[0.75] transition-transform duration-[3s] ease-out group-hover/card:scale-110"
                  loading="lazy"
                />

                <div className="absolute inset-0 bg-gradient-to-t from-black/90 via-black/10 to-transparent opacity-90 transition-opacity duration-1000" />

                <div className="absolute inset-x-4 bottom-4 p-6 rounded-[2rem] bg-white/[0.04] backdrop-blur-xl border border-white/10 shadow-2xl">
                  <div className="text-brand-gold mb-3 transition-transform duration-700 group-hover/card:-translate-y-1">
                    {point.icon}
                  </div>

                  <h3 className="font-serif text-lg text-white font-medium mb-1 tracking-tight">
                    {point.title}
                  </h3>

                  <p className="text-white/70 text-[9px] md:text-[10px] font-light leading-relaxed tracking-wide italic">
                    {point.description}
                  </p>
                </div>
              </div>
            ))}
          </div>

          {/* Indicators - Premium dots synced with scroll */}
          <div className="flex justify-center items-center gap-4 mt-8">
            {corePoints.map((_, i) => (
              <button
                key={i}
                onClick={() => handleManualNav(i)}
                className="p-2 transition-all duration-300 transform hover:scale-125"
                aria-label={`Go to feature ${i + 1}`}
              >
                <div className={`transition-all duration-700 rounded-full ${
                  activeIndex === i 
                    ? 'w-10 h-1.5 bg-brand-gold shadow-[0_0_12px_rgba(197,160,89,0.5)]' 
                    : 'w-1.5 h-1.5 bg-brand-gold/20'
                }`} />
              </button>
            ))}
          </div>

          {/* Navigation Arrows */}
          <button 
            onClick={() => handleManualNav((activeIndex - 1 + corePoints.length) % corePoints.length)}
            className="absolute left-0 top-1/2 -translate-y-1/2 opacity-0 group-hover/main:opacity-100 transition-all duration-500 bg-white/95 backdrop-blur-xl w-12 h-12 rounded-full flex items-center justify-center shadow-xl border border-black/5 text-brand-dark hover:text-brand-gold z-20 hidden md:flex"
