const Reviews: React.FC = () => {
  const [activeIndex, setActiveIndex] = useState(0);
  const [isPaused, setIsPaused] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (isPaused) return;
    const interval = setInterval(() => {
      setActiveIndex((prev) => (prev + 1) % reviews.length);
    }, 5000);
    return () => clearInterval(interval);
  }, [isPaused]);

  useEffect(() => {
    if (containerRef.current) {
      const targetElement = containerRef.current.children[activeIndex] as HTMLElement;
      if (targetElement) {
        const scrollTarget = targetElement.offsetLeft - 24;
        containerRef.current.scrollTo({
          left: scrollTarget,
          behavior: 'smooth'
        });
      }
    }
  }, [activeIndex]);

  const handleScroll = () => {
    if (containerRef.current) {
      const scrollLeft = containerRef.current.scrollLeft;
      const width = containerRef.current.children[0].clientWidth + 16; // width + gap
      const newIndex = Math.round(scrollLeft / width);
      if (newIndex !== activeIndex && newIndex >= 0 && newIndex < reviews.length) {
        setActiveIndex(newIndex);
      }
    }
  };

  const handleManualNav = (index: number) => {
    setActiveIndex(index);
    setIsPaused(true);
    setTimeout(() => setIsPaused(false), 7000);
  };

  return (
    <section 
      id="reviews" 
      className="py-16 md:py-32 bg-white overflow-hidden"
      onMouseEnter={() => setIsPaused(true)}
      onMouseLeave={() => setIsPaused(false)}
    >
      <div className="max-w-7xl mx-auto px-6">
        <SectionTitle 
          subtitle="Voices" 
          title="Reviews" 
        />

        <div className="relative group/main">
          <div 
            ref={containerRef}
            onScroll={handleScroll}
            className="flex overflow-x-auto gap-4 pb-10 snap-x snap-mandatory no-scrollbar transition-all duration-1000 scroll-smooth px-2"
          >
            {reviews.map((review) => (
              <div 
                key={review.id} 
                className="flex-shrink-0 w-[75vw] sm:w-[45vw] md:w-[320px] snap-start bg-brand-light p-8 rounded-[2rem] flex flex-col justify-between shadow-sm border border-black/[0.02]"
              >
                <div>
                  <div className="flex gap-1 mb-6 text-brand-gold">
                    {[...Array(review.rating)].map((_, i) => (
                      <Star key={i} size={12} fill="currentColor" strokeWidth={0} />
                    ))}
                  </div>
                  <p className="text-brand-dark/80 italic text-sm leading-relaxed mb-8 font-serif">
                    "{review.text}"
                  </p>
                </div>

                <div className="flex items-center gap-4 border-t border-black/[0.03] pt-6">
                  <img 
                    src={review.avatar} 
                    alt={review.name} 
                    className="w-10 h-10 rounded-full object-cover border border-white shadow-sm grayscale hover:grayscale-0 transition-all duration-700"
                  />
                  <div>
                    <h4 className="font-serif text-xs font-bold text-brand-dark leading-tight tracking-wide">{review.name}</h4>
                    <p className="text-[9px] tracking-[0.3em] text-brand-muted uppercase font-bold">{review.location}</p>
                  </div>
                </div>
              </div>
            ))}
          </div>

          {/* Indicators */}
          <div className="flex justify-center items-center gap-4 mt-8">
            {reviews.map((_, i) => (
              <button
                key={i}
                onClick={() => handleManualNav(i)}
                className="p-2"
                aria-label={`Go to review ${i + 1}`}
              >
                <div className={`transition-all duration-700 rounded-full ${
                  activeIndex === i 
                    ? 'w-10 h-1.5 bg-brand-gold shadow-[0_0_12px_rgba(197,160,89,0.5)]' 
                    : 'w-1.5 h-1.5 bg-brand-gold/10 hover:bg-brand-gold/30'
                }`} />
              </button>
            ))}
          </div>

          {/* Nav Arrows */}
          <button 
            onClick={() => handleManualNav((activeIndex - 1 + reviews.length) % reviews.length)}
            className="absolute left-0 top-1/2 -translate-y-1/2 opacity-0 group-hover/main:opacity-100 transition-all duration-500 bg-white/95 backdrop-blur-xl w-10 h-10 rounded-full flex items-center justify-center shadow-lg border border-black/5 text-brand-dark hover:text-brand-gold z-20 hidden md:flex"
          >
            <ChevronLeft size={18} />
          </button>
          <button 
            onClick={() => handleManualNav((activeIndex + 1) % reviews.length)}
            className="absolute right-0 top-1/2 -translate-y-1/2 opacity-0 group-hover/main:opacity-100 transition-all duration-500 bg-white/95 backdrop-blur-xl w-10 h-10 rounded-full flex items-center justify-center shadow-lg border border-black/5 text-brand-dark hover:text-brand-gold z-20 hidden md:flex"
          >
            <ChevronRight size={18} />
          </button>
        </div>
      </div>
    </section>
  );
};

export default Reviews;

