  },
];

const WhyAmary: React.FC = () => {
  const [activeIndex, setActiveIndex] = useState(0);
  const [isPaused, setIsPaused] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);
  const sectionRef = useRef<HTMLElement>(null);
  const hasTriggeredRef = useRef(false);

  // Auto-swipe logic every 3 seconds
  useEffect(() => {
    if (isPaused) return;
    const interval = setInterval(() => {
      setActiveIndex((prev) => (prev + 1) % corePoints.length);
    }, 3000);
    return () => clearInterval(interval);
  }, [isPaused]);

  // Scroll Entrance Trigger
  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting && !hasTriggeredRef.current) {
          hasTriggeredRef.current = true;
          // Small delay for visual impact on entry
          setTimeout(() => {
            setActiveIndex(1);
          }, 400);
        }
      },
      { threshold: 0.3 }
    );

    if (sectionRef.current) observer.observe(sectionRef.current);
    return () => observer.disconnect();
  }, []);

  // Handle activeIndex changes
  useEffect(() => {
    if (containerRef.current) {
      const targetElement = containerRef.current.children[activeIndex] as HTMLElement;
      if (targetElement) {
        const scrollTarget = targetElement.offsetLeft - 24;
        containerRef.current.scrollTo({
          left: scrollTarget,
          behavior: 'smooth'
        });
      }
    }
  }, [activeIndex]);

  const handleScroll = () => {
    if (containerRef.current) {
      const scrollLeft = containerRef.current.scrollLeft;
      const width = containerRef.current.children[0].clientWidth + 32;
      const newIndex = Math.round(scrollLeft / width);
      if (newIndex !== activeIndex && newIndex >= 0 && newIndex < corePoints.length) {
        setActiveIndex(newIndex);
      }
    }
  };

  const handleManualNav = (index: number) => {
    setActiveIndex(index);
    setIsPaused(true);
    setTimeout(() => setIsPaused(false), 8000);
  };

  return (
    <section 
      id="why-amary" 
      ref={sectionRef}
      className="py-20 md:py-32 bg-white overflow-hidden relative"
      onMouseEnter={() => setIsPaused(true)}
      onMouseLeave={() => setIsPaused(false)}
    >
      <div className="max-w-7xl mx-auto px-6">
        <SectionTitle subtitle="The Core Essence" title="Why AMARY" />

        <div className="relative group/main">
          <div 
            ref={containerRef}
            onScroll={handleScroll}
            className="flex overflow-x-auto gap-8 pb-12 snap-x snap-mandatory no-scrollbar scroll-smooth px-2"
          >
            {corePoints.map((point) => (
              <div 
                key={point.id} 
                className="flex-shrink-0 w-[65vw] sm:w-[35vw] md:w-[28vw] lg:w-[20vw] snap-start relative aspect-[4/5] rounded-[2.5rem] overflow-hidden group/card shadow-sm transition-all duration-1000 ease-[cubic-bezier(0.23,1,0.32,1)]"
              >
                <img 
                  src={point.image} 
                  alt={point.title}
                  className="w-full h-full object-cover brightness-[0.75] transition-transform duration-[3s] group-hover/card:scale-110"
                />
                <div className="absolute inset-0 bg-gradient-to-t from-black/90 via-black/10 to-transparent opacity-90" />
                <div className="absolute inset-x-4 bottom-4 p-6 rounded-[2rem] bg-white/[0.04] backdrop-blur-xl border border-white/10 shadow-2xl">
                  <div className="text-brand-gold mb-3 transition-transform duration-700 group-hover/card:-translate-y-1">
                    {point.icon}
                  </div>
                  <h3 className="font-serif text-lg text-white font-medium mb-1 tracking-tight">{point.title}</h3>
                  <p className="text-white/70 text-[10px] font-light leading-relaxed italic">{point.description}</p>
                </div>
              </div>
            ))}
          </div>

          <div className="flex justify-center items-center gap-4 mt-8">
            {corePoints.map((_, i) => (
              <button
                key={i}
                onClick={() => handleManualNav(i)}
                className="p-2 transition-all duration-300"
              >
                <div className={`transition-all duration-700 rounded-full ${
                  activeIndex === i 
                    ? 'w-10 h-1.5 bg-brand-gold shadow-[0_0_12px_rgba(197,160,89,0.5)]' 
                    : 'w-1.5 h-1.5 bg-brand-gold/20'
                }`} />
              </button>
            ))}
          </div>

          <button 
            onClick={() => handleManualNav((activeIndex - 1 + corePoints.length) % corePoints.length)}
            className="absolute left-0 top-1/2 -translate-y-1/2 opacity-0 group-hover/main:opacity-100 transition-all duration-500 bg-white/95 backdrop-blur-xl w-12 h-12 rounded-full flex items-center justify-center shadow-xl border border-black/5 text-brand-dark hover:text-brand-gold z-20 hidden md:flex"
          >
            <ChevronLeft size={20} />
          </button>
          <button 
            onClick={() => handleManualNav((activeIndex + 1) % corePoints.length)}
            className="absolute right-0 top-1/2 -translate-y-1/2 opacity-0 group-hover/main:opacity-100 transition-all duration-500 bg-white/95 backdrop-blur-xl w-12 h-12 rounded-full flex items-center justify-center shadow-xl border border-black/5 text-brand-dark hover:text-brand-gold z-20 hidden md:flex"
          >
            <ChevronRight size={20} />
          </button>
        </div>
      </div>
    </section>
  );
};

