const Fragments: React.FC = () => {
  const [activeIndex, setActiveIndex] = useState(0);
  const [isPaused, setIsPaused] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);
  const sectionRef = useRef<HTMLElement>(null);
  const hasTriggeredRef = useRef(false);
  const isInternalScroll = useRef(false);

  // Auto-swipe logic with timer reset on index change
  useEffect(() => {
    if (isPaused) return;
    const interval = setInterval(() => {
      setActiveIndex((prev) => (prev + 1) % fragments.length);
    }, 3000);
    return () => clearInterval(interval);
  }, [isPaused, activeIndex]);

  // Scroll Trigger:engaging user with a smooth swipe when section is first viewed
  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting && !hasTriggeredRef.current) {
          hasTriggeredRef.current = true;
          setTimeout(() => setActiveIndex(1), 700);
        }
      },
      { threshold: 0.3 }
    );
    if (sectionRef.current) observer.observe(sectionRef.current);
    return () => observer.disconnect();
  }, []);

  useEffect(() => {
    if (containerRef.current) {
      isInternalScroll.current = true;
      const targetElement = containerRef.current.children[activeIndex] as HTMLElement;
      if (targetElement) {
        const scrollTarget = targetElement.offsetLeft - 24;
        containerRef.current.scrollTo({
          left: scrollTarget,
          behavior: 'smooth'
        });
      }
      setTimeout(() => { isInternalScroll.current = false; }, 800);
    }
  }, [activeIndex]);

  const handleScroll = () => {
    if (containerRef.current && !isInternalScroll.current) {
      const scrollLeft = containerRef.current.scrollLeft;
      const width = containerRef.current.children[0].clientWidth + 32;
      const newIndex = Math.round(scrollLeft / width);
      if (newIndex !== activeIndex && newIndex >= 0 && newIndex < fragments.length) {
        setActiveIndex(newIndex);
      }
    }
  };

  const handleManualNav = (index: number) => {
    setActiveIndex(index);
    setIsPaused(true);
    setTimeout(() => setIsPaused(false), 8000);
  };

  return (
    <section 
      id="fragments" 
      ref={sectionRef}
      className="py-20 md:py-32 bg-white overflow-hidden relative"
      onMouseEnter={() => setIsPaused(true)}
      onMouseLeave={() => setIsPaused(false)}
    >
      <div className="max-w-7xl mx-auto px-6">
        <SectionTitle subtitle="The Archive" title="Scent Fragments" />

        <div className="relative group/main">
          <div 
            ref={containerRef}
            onScroll={handleScroll}
            className="flex overflow-x-auto gap-8 pb-12 snap-x snap-mandatory no-scrollbar scroll-smooth px-2"
          >
            {fragments.map((fragment) => (
              <div 
                key={fragment.id} 
                className="flex-shrink-0 w-[65vw] sm:w-[35vw] md:w-[28vw] lg:w-[20vw] snap-start group/card"
              >
                <div className="relative aspect-[4/5] rounded-[2.5rem] overflow-hidden bg-brand-dark shadow-sm transition-all duration-1000 ease-[cubic-bezier(0.23,1,0.32,1)] group-hover/card:shadow-xl group-hover/card:-translate-y-3">
                  <img 
                    src={fragment.image} 
                    alt={fragment.title}
                    className="w-full h-full object-cover transition-transform duration-[4s] group-hover/card:scale-110"
                    loading="lazy"
                  />
                  <div className="absolute inset-0 bg-gradient-to-t from-black/90 via-black/20 to-transparent opacity-70 group-hover/card:opacity-85" />
                  <div className="absolute inset-0 flex flex-col justify-end p-8">
                    <h3 className="font-serif text-xl text-white mb-2 transform transition-transform duration-700 group-hover/card:-translate-y-1">
                      {fragment.title}
                    </h3>
                    <p className="text-white/60 text-[10px] font-light leading-relaxed italic">
                      {fragment.subtitle}
                    </p>
                  </div>
                </div>
              </div>
            ))}
          </div>

          {/* Premium Dots Pagination */}
          <div className="flex justify-center items-center gap-4 mt-8">
            {fragments.map((_, i) => (
              <button
                key={i}
                onClick={() => handleManualNav(i)}
                className="p-2"
                aria-label={`Show fragment ${i + 1}`}
              >
                <div className={`transition-all duration-700 rounded-full ${
                  activeIndex === i 
                    ? 'w-10 h-1.5 bg-brand-gold shadow-[0_0_12px_rgba(197,160,89,0.5)]' 
                    : 'w-1.5 h-1.5 bg-brand-gold/20'
                }`} />
              </button>
            ))}
          </div>

          <button 
            onClick={() => handleManualNav((activeIndex - 1 + fragments.length) % fragments.length)}
            className="absolute left-0 top-1/2 -translate-y-1/2 opacity-0 group-hover/main:opacity-100 transition-all duration-500 bg-white/95 backdrop-blur-xl w-12 h-12 rounded-full flex items-center justify-center shadow-xl border border-black/5 text-brand-dark hover:text-brand-gold z-20 hidden md:flex"
          >
            <ChevronLeft size={20} />
          </button>
          <button 
            onClick={() => handleManualNav((activeIndex + 1) % fragments.length)}
            className="absolute right-0 top-1/2 -translate-y-1/2 opacity-0 group-hover/main:opacity-100 transition-all duration-500 bg-white/95 backdrop-blur-xl w-12 h-12 rounded-full flex items-center justify-center shadow-xl border border-black/5 text-brand-dark hover:text-brand-gold z-20 hidden md:flex"
