    category: '',
    image: 'https://ik.imagekit.io/jabzmiuta/Whisk_abc86ecd06687cda4874764be9a3edfadr.jpeg',
  },
];

const Fragments: React.FC = () => {
  const [activeIndex, setActiveIndex] = useState(0);
  const [isPaused, setIsPaused] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);
  const sectionRef = useRef<HTMLElement>(null);
  const hasTriggeredRef = useRef(false);
  const isInternalScroll = useRef(false);

  useEffect(() => {
    if (isPaused) return;
    const interval = setInterval(() => {
      setActiveIndex((prev) => (prev + 1) % fragments.length);
    }, 4000);
    return () => clearInterval(interval);
  }, [isPaused, activeIndex]);

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting && !hasTriggeredRef.current) {
          hasTriggeredRef.current = true;
          setTimeout(() => setActiveIndex(1), 1000);
        }
      },
      { threshold: 0.3 }
    );
    if (sectionRef.current) observer.observe(sectionRef.current);
    return () => observer.disconnect();
  }, []);

  useEffect(() => {
    if (containerRef.current) {
      isInternalScroll.current = true;
      const targetElement = containerRef.current.children[activeIndex] as HTMLElement;
      if (targetElement) {
        const scrollTarget = targetElement.offsetLeft - 24;
        containerRef.current.scrollTo({
          left: scrollTarget,
          behavior: 'smooth'
        });
      }
      setTimeout(() => { isInternalScroll.current = false; }, 1000);
    }
  }, [activeIndex]);

  const handleScroll = () => {
    if (containerRef.current && !isInternalScroll.current) {
      const scrollLeft = containerRef.current.scrollLeft;
      const width = containerRef.current.children[0].clientWidth + 32;
      const newIndex = Math.round(scrollLeft / width);
      if (newIndex !== activeIndex && newIndex >= 0 && newIndex < fragments.length) {
        setActiveIndex(newIndex);
      }
    }
  };

  const handleManualNav = (index: number) => {
    setActiveIndex(index);
    setIsPaused(true);
    setTimeout(() => setIsPaused(false), 10000);
  };

  return (
    <section 
      id="fragments" 
      ref={sectionRef}
      className="py-24 md:py-40 bg-white overflow-hidden relative"
      onMouseEnter={() => setIsPaused(true)}
      onMouseLeave={() => setIsPaused(false)}
    >
      <div className="max-w-7xl mx-auto px-6">
        <SectionTitle subtitle="The Archive" title="Scent Fragments" />

        <div className="relative group/main">
          <div 
            ref={containerRef}
            onScroll={handleScroll}
            className="flex overflow-x-auto gap-10 pb-20 snap-x snap-mandatory no-scrollbar scroll-smooth px-2"
          >
            {fragments.map((fragment) => (
              <div 
                key={fragment.id} 
                className="flex-shrink-0 w-[75vw] sm:w-[45vw] md:w-[32vw] lg:w-[24vw] snap-start group/card"
              >
                <div className="relative aspect-[4/5.5] rounded-[3.5rem] overflow-hidden bg-brand-dark shadow-xl transition-all duration-[1.2s] ease-[cubic-bezier(0.23,1,0.32,1)] group-hover/card:shadow-[0_60px_100px_rgba(0,0,0,0.15)] group-hover/card:-translate-y-6">
                  <img 
                    src={fragment.image} 
                    alt={fragment.title}
                    className="w-full h-full object-cover transition-transform duration-[8s] group-hover/card:scale-125"
                    loading="lazy"
                  />
                  <div className="absolute inset-0 bg-gradient-to-t from-black/100 via-black/30 to-transparent opacity-80 group-hover/card:opacity-95 transition-opacity duration-[1s]" />
                  <div className="absolute inset-0 flex flex-col justify-end p-10 transform transition-transform duration-[1s] group-hover/card:translate-y-[-10px]">
                    <h3 className="font-serif text-2xl md:text-3xl text-white mb-3 transform transition-transform duration-[1s] group-hover/card:scale-110 origin-left">
                      {fragment.title}
