interface CollectionProps {
  onSelectProduct?: (product: Product) => void;
}

const Collection: React.FC<CollectionProps> = ({ onSelectProduct }) => {
  const sectionRef = useRef<HTMLElement>(null);
  const [visibleItems, setVisibleItems] = useState<Set<string>>(new Set());

  useEffect(() => {
    const observer = new IntersectionObserver((entries) => {
      entries.forEach(entry => {
        if (entry.isIntersecting) {
          setVisibleItems(prev => new Set(prev).add(entry.target.getAttribute('data-id') || ''));
        }
      });
    }, { threshold: 0.1 });

    const items = sectionRef.current?.querySelectorAll('.product-card');
    items?.forEach(item => observer.observe(item));

    return () => observer.disconnect();
  }, []);

  return (
    <section 
      id="collections" 
      ref={sectionRef}
      className="py-12 md:py-20 bg-white relative overflow-hidden"
    >
      <div className="max-w-[1920px] mx-auto px-6 md:px-12 relative z-10">
        <div className="max-w-4xl mx-auto mb-12">
          <SectionTitle subtitle="Exclusives" title="The Collection" />
        </div>

        {/* Scaled-down Grid: 4 columns for desktop */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 md:gap-8 max-w-[1400px] mx-auto">
          {products.map((product, index) => (
            <div 
              key={product.id} 
              data-id={product.id}
              className={`product-card relative group cursor-pointer transition-all duration-[1000ms] cubic-bezier(0.23,1,0.32,1) ${
                visibleItems.has(product.id) ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-8'
              }`}
              onClick={() => onSelectProduct?.(product)}
