  },
];

const Reviews: React.FC = () => {
  const [activeIndex, setActiveIndex] = useState(0);
  const [isPaused, setIsPaused] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);
  const sectionRef = useRef<HTMLElement>(null);
  const hasTriggeredRef = useRef(false);
  const isInternalScroll = useRef(false);

  // Auto-swipe logic with reset on change
  useEffect(() => {
    if (isPaused) return;
    const interval = setInterval(() => {
      setActiveIndex((prev) => (prev + 1) % reviews.length);
    }, 3000);
    return () => clearInterval(interval);
  }, [isPaused, activeIndex]);

  // Scroll Trigger: engagements on first sight
  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting && !hasTriggeredRef.current) {
          hasTriggeredRef.current = true;
          setTimeout(() => setActiveIndex(1), 800);
        }
      },
      { threshold: 0.3 }
    );
    if (sectionRef.current) observer.observe(sectionRef.current);
    return () => observer.disconnect();
  }, []);

  useEffect(() => {
    if (containerRef.current) {
      isInternalScroll.current = true;
      const targetElement = containerRef.current.children[activeIndex] as HTMLElement;
      if (targetElement) {
        const scrollTarget = targetElement.offsetLeft - 24;
        containerRef.current.scrollTo({
          left: scrollTarget,
          behavior: 'smooth'
        });
      }
      setTimeout(() => { isInternalScroll.current = false; }, 800);
    }
  }, [activeIndex]);

  const handleScroll = () => {
    if (containerRef.current && !isInternalScroll.current) {
      const scrollLeft = containerRef.current.scrollLeft;
      const width = containerRef.current.children[0].clientWidth + 16;
      const newIndex = Math.round(scrollLeft / width);
      if (newIndex !== activeIndex && newIndex >= 0 && newIndex < reviews.length) {
        setActiveIndex(newIndex);
      }
    }
  };

  const handleManualNav = (index: number) => {
    setActiveIndex(index);
    setIsPaused(true);
    setTimeout(() => setIsPaused(false), 8000);
  };

  return (
    <section 
      id="reviews" 
      ref={sectionRef}
      className="py-16 md:py-24 bg-white overflow-hidden"
      onMouseEnter={() => setIsPaused(true)}
      onMouseLeave={() => setIsPaused(false)}
    >
      <div className="max-w-7xl mx-auto px-6">
        <SectionTitle subtitle="Voices" title="Reviews" />

        <div className="relative group/main">
          <div 
            ref={containerRef}
            onScroll={handleScroll}
            className="flex overflow-x-auto gap-4 pb-10 snap-x snap-mandatory no-scrollbar scroll-smooth px-2"
          >
            {reviews.map((review) => (
              <div 
                key={review.id} 
                className="flex-shrink-0 w-[50vw] sm:w-[30vw] md:w-[230px] snap-start bg-brand-light p-4 md:p-5 rounded-[1.2rem] flex flex-col justify-between shadow-sm border border-black/[0.01] hover:bg-white transition-all duration-700"
              >
                <div>
                  <div className="flex gap-1 mb-3 text-brand-gold">
                    {[...Array(review.rating)].map((_, i) => (
                      <Star key={i} size={8} fill="currentColor" strokeWidth={0} />
                    ))}
                  </div>
                  <p className="text-brand-dark/80 italic text-[11px] md:text-[12px] leading-relaxed mb-4 font-serif">"{review.text}"</p>
                </div>
                <div className="flex items-center gap-2.5 border-t border-black/[0.02] pt-3.5">
                  <img src={review.avatar} alt={review.name} className="w-7 h-7 rounded-full object-cover grayscale hover:grayscale-0 transition-all duration-700" />
                  <div>
                    <h4 className="font-serif text-[10px] font-bold text-brand-dark leading-tight tracking-wide">{review.name}</h4>
                    <p className="text-[7px] tracking-[0.15em] text-brand-muted uppercase font-bold">{review.location}</p>
                  </div>
                </div>
              </div>
            ))}
          </div>

          <div className="flex justify-center items-center gap-3 mt-4">
            {reviews.map((_, i) => (
              <button key={i} onClick={() => handleManualNav(i)} className="p-1.5" aria-label={`Read review ${i + 1}`}>
                <div className={`transition-all duration-700 rounded-full ${
                  activeIndex === i ? 'w-8 h-1 bg-brand-gold shadow-[0_0_10px_rgba(197,160,89,0.4)]' : 'w-1.5 h-1.5 bg-brand-gold/10'
                }`} />
              </button>
            ))}
          </div>

          <button onClick={() => handleManualNav((activeIndex - 1 + reviews.length) % reviews.length)} className="absolute left-0 top-1/2 -translate-y-1/2 opacity-0 group-hover/main:opacity-100 transition-all duration-500 bg-white/95 backdrop-blur-xl w-9 h-9 rounded-full flex items-center justify-center shadow-lg border border-black/5 text-brand-dark hidden md:flex"><ChevronLeft size={16} /></button>
          <button onClick={() => handleManualNav((activeIndex + 1) % reviews.length)} className="absolute right-0 top-1/2 -translate-y-1/2 opacity-0 group-hover/main:opacity-100 transition-all duration-500 bg-white/95 backdrop-blur-xl w-9 h-9 rounded-full flex items-center justify-center shadow-lg border border-black/5 text-brand-dark hidden md:flex"><ChevronRight size={16} /></button>
        </div>
      </div>
    </section>
  );
};

