import React, { useState, useEffect, useRef } from 'react';
import SectionTitle from './SectionTitle.tsx';
import { Review } from '../types.ts';
import { ChevronLeft, ChevronRight } from 'lucide-react';

const reviews: Review[] = [
  {
    id: '1',
