    rating: 5,
    avatar: 'https://images.unsplash.com/photo-1534528741775-53994a69daeb?q=80&w=200&auto=format&fit=crop'
  },
];

const Reviews: React.FC = () => {
  const [activeIndex, setActiveIndex] = useState(0);
  const [isPaused, setIsPaused] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);
  const sectionRef = useRef<HTMLElement>(null);
  const hasTriggeredRef = useRef(false);
  const isInternalScroll = useRef(false);

  useEffect(() => {
    if (isPaused) return;
    const interval = setInterval(() => {
      setActiveIndex((prev) => (prev + 1) % reviews.length);
    }, 4500);
    return () => clearInterval(interval);
  }, [isPaused, activeIndex]);

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting && !hasTriggeredRef.current) {
          hasTriggeredRef.current = true;
          setTimeout(() => setActiveIndex(1), 800);
        }
      },
      { threshold: 0.3 }
    );
    if (sectionRef.current) observer.observe(sectionRef.current);
    return () => observer.disconnect();
  }, []);

  useEffect(() => {
    if (containerRef.current) {
      isInternalScroll.current = true;
      const targetElement = containerRef.current.children[activeIndex] as HTMLElement;
      if (targetElement) {
        const scrollTarget = targetElement.offsetLeft - (window.innerWidth < 768 ? 24 : 48);
        containerRef.current.scrollTo({
          left: scrollTarget,
          behavior: 'smooth'
        });
      }
      setTimeout(() => { isInternalScroll.current = false; }, 800);
    }
  }, [activeIndex]);

  const handleScroll = () => {
    if (containerRef.current && !isInternalScroll.current) {
      const scrollLeft = containerRef.current.scrollLeft;
      const firstChild = containerRef.current.children[0] as HTMLElement;
      const width = firstChild ? firstChild.clientWidth + 24 : 300;
      const newIndex = Math.round(scrollLeft / width);
      if (newIndex !== activeIndex && newIndex >= 0 && newIndex < reviews.length) {
        setActiveIndex(newIndex);
      }
    }
  };

  const handleManualNav = (index: number) => {
    setActiveIndex(index);
    setIsPaused(true);
    setTimeout(() => setIsPaused(false), 10000);
  };

  return (
    <section 
      id="reviews" 
      ref={sectionRef}
      className="py-24 md:py-32 bg-white overflow-hidden selection:bg-brand-dark selection:text-white"
      onMouseEnter={() => setIsPaused(true)}
      onMouseLeave={() => setIsPaused(false)}
    >
      <div className="max-w-7xl mx-auto px-6">
        <SectionTitle subtitle="Testimonials" title="In Private Words" />

        <div className="relative group/main">
          {/* HORIZONTAL WIDE SCROLL CONTAINER */}
          <div 
            ref={containerRef}
            onScroll={handleScroll}
            className="flex overflow-x-auto gap-6 md:gap-8 pb-12 snap-x snap-mandatory no-scrollbar scroll-smooth px-2"
          >
            {reviews.map((review) => (
              <div 
                key={review.id} 
                className="flex-shrink-0 w-[85vw] md:w-[520px] snap-start bg-brand-light/30 border border-black/[0.03] p-8 md:p-10 rounded-2xl flex flex-col justify-between transition-all duration-700 hover:bg-white hover:shadow-[0_20px_40px_rgba(0,0,0,0.03)] hover:-translate-y-1 group/card"
              >
                <div className="space-y-4">
                  <h3 className="font-serif text-lg md:text-xl text-brand-dark tracking-tight">
                    {review.title}
                  </h3>
                  <p className="text-brand-dark/70 text-[13px] md:text-sm leading-relaxed font-sans max-w-lg">
                    {review.text}
                  </p>
                </div>

                <div className="mt-8 pt-6 border-t border-black/[0.02] flex items-center justify-between">
                  <div className="flex flex-col">
                    <span className="text-[10px] font-bold tracking-[0.2em] text-brand-dark uppercase">
                      {review.name}
                    </span>
                    <span className="text-[9px] tracking-[0.1em] text-brand-muted uppercase font-medium mt-0.5">
                      {review.location}
                    </span>
                  </div>

                  {/* Minimal Star Replacement - Editorial mark */}
                  <div className="w-6 h-px bg-brand-gold/30 group-hover/card:w-10 transition-all duration-700" />
                </div>
              </div>
            ))}
          </div>

          {/* DOTS */}
          <div className="flex justify-center items-center gap-4 mt-4">
            {reviews.map((_, i) => (
              <button 
                key={i} 
                onClick={() => handleManualNav(i)} 
                className="p-1.5 transition-all duration-300" 
                aria-label={`Read review ${i + 1}`}
              >
                <div className={`transition-all duration-1000 rounded-full ${
                  activeIndex === i ? 'w-10 h-1 bg-brand-gold/60' : 'w-1 h-1 bg-brand-gold/10'
                }`} />
              </button>
            ))}
          </div>

          {/* NAV BUTTONS */}
          <button 
            onClick={() => handleManualNav((activeIndex - 1 + reviews.length) % reviews.length)} 
            className="absolute -left-4 top-1/2 -translate-y-1/2 opacity-0 group-hover/main:opacity-100 transition-all duration-500 bg-white/80 backdrop-blur-md w-12 h-12 rounded-full flex items-center justify-center shadow-sm border border-black/5 text-brand-dark/40 hover:text-brand-dark hidden md:flex"
          >
            <ChevronLeft size={18} strokeWidth={1} />
          </button>
          <button 
            onClick={() => handleManualNav((activeIndex + 1) % reviews.length)} 
            className="absolute -right-4 top-1/2 -translate-y-1/2 opacity-0 group-hover/main:opacity-100 transition-all duration-500 bg-white/80 backdrop-blur-md w-12 h-12 rounded-full flex items-center justify-center shadow-sm border border-black/5 text-brand-dark/40 hover:text-brand-dark hidden md:flex"
          >
            <ChevronRight size={18} strokeWidth={1} />
          </button>
        </div>
      </div>
    </section>
  );
};

