          >
            <div className="relative aspect-[4/5] rounded-[2.5rem] overflow-hidden bg-white shadow-[0_35px_80px_rgba(0,0,0,0.07)] border border-white/70 transition-all duration-[1.8s] ease-[cubic-bezier(0.16,1,0.3,1)] group-hover:rotate-y-3 group-hover:-translate-y-3 group-hover:shadow-[0_50px_100px_rgba(0,0,0,0.1)]">
              <img 
                src={product.image} 
