const Fragments: React.FC = () => {
  const [activeIndex, setActiveIndex] = useState(0);
  const [isPaused, setIsPaused] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);
  const sectionRef = useRef<HTMLElement>(null);
  const hasTriggeredRef = useRef(false);
  const isInternalScroll = useRef(false);

  useEffect(() => {
    if (isPaused) return;
    const interval = setInterval(() => {
      setActiveIndex((prev) => (prev + 1) % fragments.length);
    }, 4500);
    return () => clearInterval(interval);
  }, [isPaused, activeIndex]);

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting && !hasTriggeredRef.current) {
          hasTriggeredRef.current = true;
          setTimeout(() => setActiveIndex(1), 800);
        }
      },
      { threshold: 0.3 }
    );
    if (sectionRef.current) observer.observe(sectionRef.current);
    return () => observer.disconnect();
  }, []);

  useEffect(() => {
    if (containerRef.current) {
      isInternalScroll.current = true;
      const targetElement = containerRef.current.children[activeIndex] as HTMLElement;
      if (targetElement) {
        const scrollTarget = targetElement.offsetLeft - (window.innerWidth < 768 ? 24 : 48);
        containerRef.current.scrollTo({
          left: scrollTarget,
          behavior: 'smooth'
        });
      }
      setTimeout(() => { isInternalScroll.current = false; }, 800);
    }
  }, [activeIndex]);

  const handleManualNav = (index: number) => {
    setActiveIndex(index);
    setIsPaused(true);
    setTimeout(() => setIsPaused(false), 12000);
  };

  return (
    <section 
      id="fragments" 
      ref={sectionRef}
      className="py-24 md:py-36 bg-white overflow-hidden relative"
      onMouseEnter={() => setIsPaused(true)}
      onMouseLeave={() => setIsPaused(false)}
    >
      <div className="max-w-7xl mx-auto px-6">
        <SectionTitle subtitle="The Archive" title="Scent Fragments" />

        <div className="relative group/main">
          <div 
            ref={containerRef}
            className="flex overflow-x-auto gap-8 pb-16 snap-x snap-mandatory no-scrollbar scroll-smooth px-2"
          >
            {fragments.map((fragment, idx) => (
              <div 
                key={fragment.id} 
                className={`flex-shrink-0 w-[65vw] sm:w-[35vw] md:w-[25vw] lg:w-[19vw] snap-start group/card transition-all duration-[1.2s] ease-[cubic-bezier(0.23,1,0.32,1)] ${hasTriggeredRef.current ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-12'}`}
                style={{ transitionDelay: `${idx * 150}ms` }}
              >
                <div className="relative aspect-[3/4] rounded-[2.8rem] overflow-hidden bg-brand-dark shadow-md transition-all duration-[1.2s] group-hover/card:shadow-2xl group-hover/card:-translate-y-3">
                  <img 
                    src={fragment.image} 
                    alt={fragment.title}
                    className="w-full h-full object-cover transition-transform duration-[6s] group-hover/card:scale-115"
                    loading="lazy"
                  />
                  <div className="absolute inset-0 bg-gradient-to-t from-black/95 via-black/20 to-transparent opacity-80" />
                  <div className="absolute inset-0 flex flex-col justify-end p-8">
                    <span className="text-[7px] font-bold tracking-[0.5em] text-brand-gold/60 uppercase mb-2">{fragment.volume}</span>
                    <h3 className="font-serif text-xl text-white mb-2 transform transition-transform duration-1000 group-hover/card:-translate-y-1.5">
                      {fragment.title}
                    </h3>
                    <p className="text-white/50 text-[10px] font-light leading-relaxed italic max-w-[90%]">
                      {fragment.subtitle}
                    </p>
                  </div>
                </div>
              </div>
            ))}
          </div>

          <div className="flex justify-center items-center gap-6 mt-4">
            {fragments.map((_, i) => (
              <button key={i} onClick={() => handleManualNav(i)} className="p-2 transition-all duration-300">
                <div className={`transition-all duration-[1.2s] rounded-full ${
                  activeIndex === i 
                    ? 'w-12 h-1.5 bg-brand-gold shadow-[0_0_15px_rgba(197,160,89,0.4)]' 
                    : 'w-1.5 h-1.5 bg-brand-gold/15'
                }`} />
              </button>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
};

