  const intervalRef = useRef<ReturnType<typeof setInterval>>();

  // Auto-scroll logic
  const startScrolling = () => {
    intervalRef.current = setInterval(() => {
      if (containerRef.current) {
        const { scrollLeft, scrollWidth, clientWidth } = containerRef.current;
