          onClick={handleBack}
          className="w-10 h-10 flex items-center justify-center rounded-full hover:bg-white/50 text-brand-dark/60 hover:text-brand-dark transition-all active:scale-95"
          aria-label="Back"
        >
          <ArrowLeft size={18} strokeWidth={1.5} />
